import numpy as np

def hungarian_algorithm(cost_matrix):
    cost_matrix = np.array(cost_matrix, dtype=float)
    n_rows_orig, n_cols_orig = cost_matrix.shape

    if n_rows_orig == 0 or n_cols_orig == 0:
        return []

    n = max(n_rows_orig, n_cols_orig)

    padding_value = np.max(cost_matrix) + 1.0 if cost_matrix.size > 0 else 1e10

    padded_cost_matrix = np.full((n, n), padding_value)
    padded_cost_matrix[:n_rows_orig, :n_cols_orig] = cost_matrix
    cost_matrix = padded_cost_matrix

    for i in range(n):
        min_val = np.min(cost_matrix[i, :])
        cost_matrix[i, :] -= min_val

    for j in range(n):
        min_val = np.min(cost_matrix[:, j])
        cost_matrix[:, j] -= min_val

    mask = np.zeros((n, n), dtype=int)
    row_covered = np.zeros(n, dtype=bool)
    col_covered = np.zeros(n, dtype=bool)

    def find_uncovered_zero():
        for i in range(n):
            for j in range(n):
                if cost_matrix[i, j] == 0 and not row_covered[i] and not col_covered[j]:
                    return i, j
        return -1, -1

    def find_min_uncovered():
        min_val = np.inf
        for i in range(n):
            for j in range(n):
                if not row_covered[i] and not col_covered[j]:
                    if cost_matrix[i, j] < min_val:
                        min_val = cost_matrix[i, j]
        return min_val

    def find_star_in_row(r):
        for j in range(n):
            if mask[r, j] == 1:
                return j
        return -1

    def find_star_in_col(c):
        for i in range(n):
            if mask[i, c] == 1:
                return i
        return -1

    state = "STEP_STAR_ZEROS"
    path = []
    path_row_0, path_col_0 = -1, -1

    while True:
        if state == "STEP_STAR_ZEROS":
            for i in range(n):
                for j in range(n):
                    if cost_matrix[i, j] == 0 and not row_covered[i] and not col_covered[j]:
                        mask[i, j] = 1
                        row_covered[i] = True
                        col_covered[j] = True

            row_covered.fill(False)
            col_covered.fill(False)
            state = "STEP_COVER_COLUMNS"

        elif state == "STEP_COVER_COLUMNS":
            col_covered.fill(False)
            for j in range(n):
                if np.any(mask[:, j] == 1):
                    col_covered[j] = True

            num_covered_cols = np.sum(col_covered)
            if num_covered_cols == n:
                break
            else:
                state = "STEP_FIND_PRIME"

        elif state == "STEP_FIND_PRIME":
            r, c = find_uncovered_zero()
            if r == -1:
                state = "STEP_ADJUST_MATRIX"
            else:
                mask[r, c] = 2
                star_c = find_star_in_row(r)
                if star_c != -1:
                    row_covered[r] = True
                    col_covered[star_c] = False
                else:
                    path_row_0, path_col_0 = r, c
                    state = "STEP_AUGMENT_PATH"

        elif state == "STEP_AUGMENT_PATH":
            path = [(path_row_0, path_col_0)]

            done = False
            while not done:
                r_star = find_star_in_col(path[-1][1])
                if r_star == -1:
                    done = True
                else:
                    path.append((r_star, path[-1][1]))
                    c_prime = -1
                    for j in range(n):
                        if mask[r_star, j] == 2:
                            c_prime = j
                            break
                    path.append((r_star, c_prime))

            for r_path, c_path in path:
                if mask[r_path, c_path] == 1:
                    mask[r_path, c_path] = 0
                else:
                    mask[r_path, c_path] = 1

            mask[mask == 2] = 0
            row_covered.fill(False)
            col_covered.fill(False)
            path = []
            state = "STEP_COVER_COLUMNS"

        elif state == "STEP_ADJUST_MATRIX":
            min_val = find_min_uncovered()

            for i in range(n):
                for j in range(n):
                    if row_covered[i]:
                        cost_matrix[i, j] += min_val
                    if not col_covered[j]:
                        cost_matrix[i, j] -= min_val
            state = "STEP_FIND_PRIME"

    assignments = []
    for i in range(n_rows_orig):
        for j in range(n_cols_orig):
            if mask[i, j] == 1:
                assignments.append((i, j))

    return assignments
